                            "code": "# === ENTRY-LEVEL EXAMPLE ===\n# TASK      - Basic usage of Self Type — Methods Returning the Current Class — understand the core syntax and behavior.\n# APPROACH  - Simple example with minimal parameters; no edge cases.\n# STRENGTHS - Clear, readable; shows the fundamental pattern.\n# WEAKNESSES- Not production-ready; no error handling or complex scenarios.\nfrom typing import Self\nclass QueryBuilder:\n    def __init__(self) -> None:\n        self._sel: list[str] = []\n        self._where: list[str] = []\n    def select(self, *cols: str) -> Self:\n        self._sel.extend(cols);  return self\n    def where(self, cond: str) -> Self:\n        self._where.append(cond);  return self\n    def build(self) -> str:\n        s = \", \".join(self._sel) or \"*\"\n        w = \" AND \".join(self._where)\n        return f\"SELECT {s}\" + (f\" WHERE {w}\" if w else \"\")\n# Chained calls keep the exact class type:\nsql = QueryBuilder().select(\"id\", \"name\").where(\"age > 18\").build()"
