          concise: "@runtime_checkable\nclass Drawable(Protocol):\n    def draw(self) -> None: ...\n\ndef draw_shape(shape: Any) -> None:\n    if isinstance(shape, Drawable):\n        shape.draw()\n    else:\n        raise TypeError(f\"{type(shape)} not Drawable\")",
